{"content": "import { Header } from "@/components/header"
import { Footer } from "@/components/footer"
import { MobileCta } from "@/components/mobile-cta"
import { CtaBanner } from "@/components/cta-banner"
import { ProcessSection } from "@/components/process-section"
import { WhatsAppFloat } from "@/components/whatsapp-float"
import type { Content } from "@/types/content"
import raw from "@/content/es.json"

const content = raw as unknown as Content
const h = content.home
const hero = h.hero
const stats = h.stats.items
const features = h.features
const services = h.services
const portfolio = h.portfolio
const clients = h.clients
const books = h.books
const testimonials = h.testimonials
const process = h.process
const cta = h.finalCta
const phone = content.whatsapp.phone

function matchesPortfolio(testimonial: { book?: string }): string | undefined {
  if (!testimonial.book) return undefined
  const match = portfolio.items.find(
    (p) => testimonial.book && p.title.toLowerCase().includes(testimonial.book.toLowerCase().slice(0, 20))
  )
  return match?.image
}

const authorPhotos: Record<string, string> = {
  "Paula Da Rocha": "",
  "Mónica Rodríguez": "",
  "Denisse Quiñones": "",
  "Gimena Bazante": "",
  "J.M. Sileiray": "",
}

export default function Home() {
  const bgStyle = hero.image
    ? { backgroundImage: `linear-gradient(rgba(0,0,0,0.65), rgba(0,0,0,0.5)), url(${hero.image})`, backgroundSize: "cover", backgroundPosition: "center" }
    : { backgroundColor: "var(--color-primary)" }

  return (
    <>
      <div id="main-content">
      <Header />

      <section className="relative flex min-h-[85vh] items-center justify-center overflow-hidden" style={bgStyle}>
        <div className="relative z-10 mx-auto max-w-4xl px-4 text-center">
          <div className="rounded-2xl bg-black/20 p-8 backdrop-blur-sm sm:p-12">
            <h1 className="mb-4 text-4xl font-bold tracking-tight text-white sm:text-5xl">
              {hero.headlineTest || hero.headline || "La portada que tu libro se merece"}
            </h1>
            {hero.subheadline && <p className="mx-auto mb-8 max-w-2xl text-lg text-white/90">{hero.subheadline}</p>}
            <div className="flex flex-col items-center gap-4 sm:flex-row sm:justify-center">
              <a href={hero.ctaPrimaryHref || "/servicios"}
                className="inline-flex h-12 items-center justify-center rounded-md bg-secondary px-10 text-sm font-semibold text-secondary-foreground shadow-xs transition-all hover:bg-secondary/90 hover:scale-105">
                {hero.ctaPrimaryText}
              </a>
              <a href={hero.ctaSecondaryHref || `/premades`} target="_blank" rel="noopener noreferrer"
                className="inline-flex h-12 items-center justify-center rounded-md border-2 border-white/80 px-10 text-sm font-semibold text-white transition-all hover:bg-white/20 hover:scale-105">
                {hero.ctaSecondaryText}
              </a>
            </div>
          </div>
        </div>
      </section>

      {stats.length > 0 && (
        <section className="bg-surface py-12">
          <div className="mx-auto max-w-7xl px-4">
            <div className={`grid gap-8 sm:gap-10 ${stats.length === 4 ? 'grid-cols-2 sm:grid-cols-4' : 'grid-cols-3'}`}>
              {stats.map((s, i) => (
                <div key={i} className="text-center">
                  <div className="text-4xl font-bold text-primary sm:text-5xl">{s.value}</div>
                  <div className="mt-2 text-sm font-medium text-muted-foreground">{s.label}</div>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {features.items.length > 0 && (
        <section className="bg-background py-20">
          <div className="mx-auto max-w-7xl px-4">
            {features.title && <h2 className="mb-12 text-center text-3xl font-bold text-foreground">{features.title}</h2>}
            <div className="grid gap-8 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5">
              {features.items.map((f, i) => (
                <div key={i} className="group rounded-xl border border-border bg-surface p-6 text-center transition-all hover:-translate-y-2 hover:shadow-lg">
                  <div className="mx-auto mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-primary/10 text-primary transition-all group-hover:bg-primary group-hover:text-primary-foreground">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>
                  </div>
                  <h3 className="mb-2 font-semibold text-foreground">{f.title}</h3>
                  <p className="text-sm text-muted-foreground">{f.description}</p>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {portfolio.items.length > 0 && (
        <section className="bg-surface py-20">
          <div className="mx-auto max-w-7xl px-4">
            {portfolio.title && <h2 className="mb-2 text-center text-3xl font-bold text-foreground">{portfolio.title}</h2>}
            {portfolio.subtitle && <p className="mb-10 text-center text-muted-foreground">{portfolio.subtitle}</p>}
            <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
              {portfolio.items.map((item, i) => (
                <a key={i} href={`/portafolio/${item.slug}`}
                  className="group overflow-hidden rounded-xl border border-border bg-white shadow-sm transition-all hover:-translate-y-2 hover:shadow-xl">
                  <div className="aspect-[5/8] overflow-hidden bg-surface">
                    <img src={item.image} alt={item.title} loading="lazy" className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-110" />
                  </div>
                  <div className="p-4">
                    <h3 className="font-semibold text-foreground">{item.title}</h3>
                    <p className="text-sm text-muted-foreground">{item.genre}</p>
                  </div>
                </a>
              ))}
            </div>
            <div className="mt-10 text-center">
              <a href="/portafolio" className="text-sm font-medium text-primary hover:underline">Ver todos los trabajos →</a>
            </div>
          </div>
        </section>
      )}

      {clients && clients.editorials && (
        <section className="bg-background py-20">
          <div className="mx-auto max-w-7xl px-4">
            {clients.title && <h2 className="mb-2 text-center text-3xl font-bold text-foreground">{clients.title}</h2>}
            {clients.subtitle && <p className="mb-10 text-center text-muted-foreground">{clients.subtitle}</p>}
            <div className="grid gap-8 md:grid-cols-2">
              {clients.editorials.length > 0 && (
                <div className="rounded-xl border border-border bg-surface p-8">
                  <h3 className="mb-6 text-center text-lg font-bold text-foreground">Editoriales</h3>
                  <div className="flex flex-wrap items-center justify-center gap-8">
                    {(() => {
                      const logoMap: Record<string, string> = {
                        "Editorial Blanco y Negro SAS (Colombia)": "/dayah/logos/editorial-blanco-negro.png",
                        "Castell Ediciones (Paraguay)": "/dayah/logos/castell-ediciones.png",
                        "Arandura Editorial (Paraguay)": "/dayah/logos/arandura.png",
                        "El Lector (Paraguay)": "/dayah/logos/el-lector.png",
                      }
                      return clients.editorials.map((e, i) => {
                        const logo = logoMap[e]
                        return logo ? (
                          <div key={i} className="flex items-center justify-center rounded-xl bg-white p-5 shadow-sm" style={{ width: 180, height: 90 }}>
                            <img src={logo} alt={e} className="max-h-14 max-w-[160px] object-contain" />
                          </div>
                        ) : (
                          <div key={i} className="flex items-center gap-3 rounded-lg bg-white px-4 py-3 shadow-sm">
                            <span className="font-medium text-foreground">{e}</span>
                          </div>
                        )
                      })
                    })()}
                  </div>
                </div>
              )}
              {clients.authors.length > 0 && (
                <div className="rounded-xl border border-border bg-surface p-8">
                  <h3 className="mb-6 text-center text-lg font-bold text-foreground">Autores Bestseller</h3>
                  <div className="space-y-3">
                    {clients.authors.map((a, i) => (
